proof_block:
// Re-instantiate both `forall|i|` antecedents with explicit triggers so z3
// fires them on the same skolem `i`. The antecedent provides two disjoint
// triggers (post1_self_.page_array@[i] vs post2_self_.page_array@[i]); we
// pull both into the proof context here.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// At i == index, every field of post1_self_.page_array@[index] and
// post2_self_.page_array@[index] is pinned by the antecedent: the scalar
// fields (addr/state/is_io_page/rev_pointer/ref_count) equal pre_self_'s,
// owning_container equals owning_container_op, and the ghost fields
// (mappings/io_mappings) are =~= pre_self_'s. So the two Page values agree
// field-by-field, i.e. they are =~= equal.
assert(post1_self_.page_array@[index as int] =~= post2_self_.page_array@[index as int]);

// Pointwise equality of the two array views, with an explicit case split
// on whether i is the modified index.
assert forall|i: int|
    0 <= i < NUM_PAGES implies post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Closed by the field-wise Page equality at `index` above.
    } else {
        // Both post1_self_.page_array@[i] and post2_self_.page_array@[i]
        // are =~= pre_self_.page_array@[i] (from the re-asserted foralls),
        // hence =~= each other by transitivity.
    }
};

// Sequence extensionality lifts the pointwise equality to the .view().
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
